class Solution {
public:
    int strangePrinter(string s) {
        int n = s.size();
        vector<int> dp(n + 1, 1);
        for (int i = 1; i <= n; ++i) {
            for (int j = 0; j < i; ++j) {
                if (s[i - 1] == s[j]) {
                    dp[i] = min(dp[i], dp[j] + 1);
                }
            }
        }
        return dp[n];
    }
};
